var sync_uuid = (Date.now().toString(36).toUpperCase().slice(-4) + Math.random().toString(36).substring(2,6).toUpperCase() + Math.random().toString(36).substring(2,6).toUpperCase());
msg.sync_uuid = sync_uuid;

var q = ""
+ "SELECT TOP 300\n"
+ "    CODIGO AS CUIT,\n"
+ "    NOMBREDESTINATARIO AS PROVEEDOR,\n"
+ "    '' AS CATEGORIA,\n"
+ "    ISNULL(SUM(SALDODOCUMENTO), 0) AS SALDO,\n"
+ "    0.0 AS VENCIDO,\n"
+ "    0.0 AS A_VENCER,\n"
+ "    MAX(SUBSTRING(FECHAACTUAL, 1, 8)) AS ULTIMO_MOV,\n"
+ "    ISNULL(UN, '') AS UNIDAD_NEGOCIO\n"
+ "FROM V_EZI_PROV_CTA_CTE\n"
+ "WHERE SALDODOCUMENTO <> 0\n"
+ "GROUP BY CODIGO, NOMBREDESTINATARIO, UN\n"
+ "ORDER BY SALDO ASC;\n";

msg.payload = q;
node.warn('[Sync-PS] Preparando sync ' + sync_uuid);
return msg;

var rows = msg.payload;
var sync_uuid = msg.sync_uuid || 'N/A';
var timestamp = new Date().toISOString();
msg._syncInfo = { sync_uuid: sync_uuid, timestamp: timestamp };
if (!rows || !Array.isArray(rows) || rows.length === 0) {
  node.warn('[Sync-PS] Sin datos.'); msg._syncInfo.empty = true; msg.payload = null; return msg;
}
// Columnas A-J: CUIT|PROVEEDOR|CATEGORIA|SALDO|VENCIDO|A_VENCER|ULTIMO_MOV|ESTADO|UNIDAD_NEGOCIO|SYNC_UUID
var data = [];
for (var i = 0; i < rows.length; i++) {
  var r = rows[i]; if (!r) continue;
  var saldo = parseFloat(r.SALDO) || 0;
  data.push([
    (r.CUIT || '').toString().trim(),
    (r.PROVEEDOR || '').toString().trim(),
    (r.CATEGORIA || '').toString().trim(),
    saldo,
    parseFloat(r.VENCIDO) || 0,
    parseFloat(r.A_VENCER) || 0,
    (r.ULTIMO_MOV || '').toString().trim(),
    saldo < 0 ? 'ok' : 'warn',
    (r.UNIDAD_NEGOCIO || '').toString().trim(),
    sync_uuid
  ]);
}
msg._sheetData = data; msg.payload = data;
msg._syncInfo.rowCount = data.length;
node.warn('[Sync-PS] ' + data.length + ' proveedores. UUID=' + sync_uuid);
return msg;

// El GSheet Clear sobreescribe msg.payload con la respuesta de la API
// Restaurar el array 2D desde _sheetData para que el Append funcione
if (msg._sheetData) {
  msg.payload = msg._sheetData;
}
return msg;

var info = msg._syncInfo || {};
if (info.empty) {
  node.warn('[Sync-ps] Sync omitido: sin datos');
  return msg;
}
if (msg.error) {
  node.error('[Sync-ps] ERROR: ' + msg.error);
  return msg;
}
var updatedRange = '';
if (msg.payload && msg.payload.updates) updatedRange = msg.payload.updates.updatedRange || '';
node.warn('[Sync-ps] ✅ Sync exitoso — ' + (info.rowCount || 0) + ' filas → ProveedoresSaldos');
node.warn('[Sync-ps]    UUID: ' + (info.sync_uuid || '?') + ' | Rango: ' + updatedRange);
return msg;
